      'evaluation_4mark': [
        {'question': 'ফরাসি বিপ্লবে নারীদের অংশগ্রহণের গুরুত্ব বিশ্লেষণ কর।', 'answer': 'ফরাসি বিপ্লবে নারীদের অংশগ্রহণ ছিল গুরুত্বপূর্ণ ও বহুমাত্রিক। প্রথমত, ১৭৮৯-এর অক্টোবর নারীদের ভার্সাই অভিযান রাজতন্ত্রের ভিত কাঁপিয়ে দেয় — রাজপরিবারকে প্যারিসে আসতে বাধ্য করে, যা কার্যত রাজাকে বন্দি করে তোলে। দ্বিতীয়ত, জিরন্ডিস্ট ও জ্যাকোবিন উভয় দলেই নারী নেত্রীরা সক্রিয় ভূমিকা রাখেন — মাদাম রঁলা, পাওলিন লিওন প্রমুখ রাজনৈতিক সেলুন ও সভা সমাবেশের মাধ্যমে বিপ্লবী চিন্তা ছড়িয়ে দেন। তৃতীয়ত, সোসাইটি অফ রেভল্যুশনারি রিপাবলিক উইমেন-এর মতো সংগঠনের মাধ্যমে নারীরা সুসংগঠিত আন্দোলন গড়ে তোলে। চতুর্থত, মেরি আলম্প দ্য গুজ ও এত্তা পাম দ্য এলডারস-এর মতো নারীবাদী লেখিকারা নারী অধিকারের তাত্ত্বিক ভিত্তি তৈরি করেন। পঞ্চমত, সরকারি সশস্ত্র বাহিনী নারী আন্দোলন দমন করতে ব্যর্থ হয় — যা প্রমাণ করে নারী আন্দোলন কতটা শক্তিশালী ছিল। তবে জ্যাকোবিন শাসন নারী সংগঠন নিষিদ্ধ করে এবং নেত্রীদের হত্যা করে — যা দেখায় যে বিপ্লবের মধ্যেও নারীদের প্রতি বৈষম্য ছিল।', 'marks': 4},
        {'question': 'ফরাসি বিপ্লবের আদর্শ নারী আন্দোলনে কী প্রভাব ফেলেছিল?', 'answer': 'ফরাসি বিপ্লবের মূল আদর্শ — স্বাধীনতা, সমতা ও ভ্রাতৃত্ব — নারীদের গভীরভাবে প্রভাবিত করেছিল। যদি সব মানুষ স্বাধীন ও সমান হয়, তাহলে নারীরা কেন পুরুষের অধীন থাকবে — এই প্রশ্ন নারীদের মনে জাগে। বিপ্লবের আদর্শ নারীদের সংগঠিত হতে ও তাদের অধিকার দাবি করতে অনুপ্রাণিত করে। নারীরা বুঝতে পারে যে পুরুষ আধিপত্য একটি সামাজিক নির্মাণ, যা পরিবর্তনযোগ্য। বিপ্লবের সময় নারীরা রাস্তায় নেমে — মিছিল, দাঙ্গা, রাজনৈতিক সভা ও লেখালেখির মাধ্যমে তাদের দাবি জানায়। তবে বিপ্লবী নেতৃত্ব — বিশেষ করে জ্যাকোবিনরা — নারীদের প্রতি সমান অধিকার প্রসারে ব্যর্থ হয়। বিপ্লবের আদর্শে উদ্বুদ্ধ হয়েও নারীরা অবিলম্বে ভোটাধিকার বা রাজনৈতিক অধিকার পায়নি। কিন্তু ফরাসি বিপ্লবের এই নারী জাগরণ পরবর্তী শতাব্দীতে নারী আন্দোলনের জন্য একটি শক্ত ভিত্তি তৈরি করে।', 'marks': 4},
        {'question': 'ফরাসি বিপ্লবে নারীদের সক্রিয় ভূমিকা ও জ্যাকোবিন শাসনে তাদের দমনের মধ্যে বৈপরীত্য বিশ্লেষণ কর।', 'answer': 'ফরাসি বিপ্লবের প্রথম দিকে নারীরা ছিল অত্যন্ত সক্রিয় — তারা ১৭৮৯-এর অক্টোবর মিছিলে নেতৃত্ব দেয়, রাজনৈতিক ক্লাবে যোগ দেয়, পুস্তিকা রচনা করে এবং দাঙ্গাহাঙ্গামায় অংশ নেয়। জিরন্ডিস্ট ও জ্যাকোবিন উভয় দলেই নারী নেত্রী ছিল। এই সক্রিয়তা প্রমাণ করে যে বিপ্লবের প্রাথমিক ধাপে নারীদের স্থান ছিল গুরুত্বপূর্ণ। কিন্তু জ্যাকোবিন শাসনে (১৭৯৩-১৭৯৪) এই পরিস্থিতি সম্পূর্ণ বদলে যায়। জ্যাকোবিনরা নারী সংগঠন নিষিদ্ধ করে। মাদাম রঁলা-সহ বহু নেত্রীকে গ্রেফতার করে মৃত্যুদণ্ড দেওয়া হয়। নারীদের রাজনৈতিক অধিকার কেড়ে নেওয়া হয়। এই বৈপরীত্যের কারণ: জ্যাকোবিনরা বিপ্লবের স্থায়িত্বের জন্য কঠোর নিয়ন্ত্রণ প্রয়োজন মনে করত। তারা নারীদের রাজনৈতিক সক্রিয়তাকে "বিপ্লবের জন্য হুমকি" হিসেবে দেখত। অথচ বিপ্লবের শুরুতে নারীরাই ছিল বিপ্লবের অন্যতম চালিকাশক্তি। এই বৈপরীত্য ফরাসি বিপ্লবের সীমাবদ্ধতা ও বুর্জোয়া চরিত্রকে তুলে ধরে — বিপ্লব স্বাধীনতা ও সমতার কথা বললেও নারী ও অন্যান্য প্রান্তিক গোষ্ঠীর প্রতি তা সমান ছিল না।', 'marks': 4},
